     1→use nom::Parser;
     2→use nom::{
     3→    IResult,
     4→    branch::alt,
     5→    bytes::complete::{tag, take_while, take_while1},
     6→    character::complete::{char, multispace0},
     7→    combinator::{map, opt, recognize},
     8→    multi::separated_list1,
     9→    sequence::preceded,
    10→};
    11→
    12→use crate::ast::{CmpOp, Expr, FieldPath, Value};
    13→use crate::error::QueryError;
    14→
    15→fn ws<'a, F, O>(mut inner: F) -> impl FnMut(&'a str) -> IResult<&'a str, O>
    16→where
    17→    F: Parser<&'a str, Output = O, Error = nom::error::Error<&'a str>>,
    18→{
    19→    move |input: &'a str| {
    20→        let (input, _) = multispace0.parse(input)?;
    21→        let (input, val) = inner.parse(input)?;
    22→        let (input, _) = multispace0.parse(input)?;
    23→        Ok((input, val))
    24→    }
    25→}
    26→
    27→fn is_ident_start(c: char) -> bool {
    28→    c.is_ascii_alphabetic() || c == '_'
    29→}
    30→
    31→fn is_ident_cont(c: char) -> bool {
    32→    c.is_ascii_alphanumeric() || c == '_'
    33→}
    34→
    35→fn ident(input: &str) -> IResult<&str, &str> {
    36→    recognize((
    37→        take_while1(|c: char| is_ident_start(c)),
    38→        take_while(|c: char| is_ident_cont(c)),
    39→    ))
    40→    .parse(input)
    41→}
    42→
    43→fn field_path(input: &str) -> IResult<&str, FieldPath> {
    44→    map(separated_list1(char('.'), ident), |parts| {
    45→        FieldPath(parts.into_iter().map(String::from).collect())
    46→    })
    47→    .parse(input)
    48→}
    49→
    50→fn string_lit(input: &str) -> IResult<&str, String> {
    51→    let (input, _) = char('"').parse(input)?;
    52→    let mut result = String::new();
    53→    let mut chars = input.chars();
    54→    let mut rest_start = 0;
    55→    while let Some(c) = chars.next() {
    56→        rest_start += c.len_utf8();
    57→        if c == '\\' {
    58→            if let Some(escaped) = chars.next() {
    59→                rest_start += escaped.len_utf8();
    60→                match escaped {
    61→                    'n' => result.push('\n'),
    62→                    't' => result.push('\t'),
    63→                    '\\' => result.push('\\'),
    64→                    '"' => result.push('"'),
    65→                    _ => {
    66→                        result.push('\\');
    67→                        result.push(escaped);
    68→                    }
    69→                }
    70→            }
    71→        } else if c == '"' {
    72→            return Ok((&input[rest_start..], result));
    73→        } else {
    74→            result.push(c);
    75→        }
    76→    }
    77→    Err(nom::Err::Error(nom::error::Error::new(
    78→        input,
    79→        nom::error::ErrorKind::Char,
    80→    )))
    81→}
    82→
    83→fn number_lit(input: &str) -> IResult<&str, f64> {
    84→    let (input, neg) = opt(char('-')).parse(input)?;
    85→    let (input, int_part) = take_while1(|c: char| c.is_ascii_digit()).parse(input)?;
    86→    let (input, frac) =
    87→        opt(preceded(char('.'), take_while1(|c: char| c.is_ascii_digit()))).parse(input)?;
    88→
    89→    let mut s = String::new();
    90→    if neg.is_some() {
    91→        s.push('-');
    92→    }
    93→    s.push_str(int_part);
    94→    if let Some(f) = frac {
    95→        s.push('.');
    96→        s.push_str(f);
    97→    }
    98→    match s.parse::<f64>() {
    99→        Ok(n) => Ok((input, n)),
   100→        Err(_) => Err(nom::Err::Error(nom::error::Error::new(
   101→            input,
   102→            nom::error::ErrorKind::Float,
   103→        ))),
   104→    }
   105→}
   106→
   107→fn bool_lit(input: &str) -> IResult<&str, bool> {
   108→    alt((map(tag("true"), |_| true), map(tag("false"), |_| false))).parse(input)
   109→}
   110→
   111→fn value(input: &str) -> IResult<&str, Value> {
   112→    alt((
   113→        map(string_lit, Value::String),
   114→        map(bool_lit, Value::Bool),
   115→        map(number_lit, Value::Number),
   116→    ))
   117→    .parse(input)
   118→}
   119→
   120→fn cmp_op(input: &str) -> IResult<&str, CmpOp> {
   121→    alt((
   122→        map(tag("=="), |_| CmpOp::Eq),
   123→        map(tag("!="), |_| CmpOp::Ne),
   124→        map(tag(">="), |_| CmpOp::Ge),
   125→        map(tag("<="), |_| CmpOp::Le),
   126→        map(tag(">"), |_| CmpOp::Gt),
   127→        map(tag("<"), |_| CmpOp::Lt),
   128→    ))
   129→    .parse(input)
   130→}
   131→
   132→fn paren_expr(input: &str) -> IResult<&str, Expr> {
   133→    let (input, _) = multispace0.parse(input)?;
   134→    let (input, _) = char('(').parse(input)?;
   135→    let (input, _) = multispace0.parse(input)?;
   136→    let (input, expr) = or_expr(input)?;
   137→    let (input, _) = multispace0.parse(input)?;
   138→    let (input, _) = char(')').parse(input)?;
   139→    Ok((input, expr))
   140→}
   141→
   142→fn not_expr(input: &str) -> IResult<&str, Expr> {
   143→    let (input, _) = multispace0.parse(input)?;
   144→    let (input, _) = char('!').parse(input)?;
   145→    let (input, _) = multispace0.parse(input)?;
   146→    let (input, inner) = atom(input)?;
   147→    Ok((input, Expr::Not(Box::new(inner))))
   148→}
   149→
   150→fn atom(input: &str) -> IResult<&str, Expr> {
   151→    if let Ok(result) = paren_expr(input) {
   152→        return Ok(result);
   153→    }
   154→    if let Ok(result) = not_expr(input) {
   155→        return Ok(result);
   156→    }
   157→    field_expr(input)
   158→}
   159→
   160→fn field_expr(input: &str) -> IResult<&str, Expr> {
   161→    let (input, field) = ws(field_path).parse(input)?;
   162→
   163→    // Try `contains "string"`
   164→    if let Ok((rest, _)) = tag::<&str, &str, nom::error::Error<&str>>("contains").parse(input)
   165→        && let Ok((rest, sub)) = ws(string_lit).parse(rest)
   166→    {
   167→        return Ok((
   168→            rest,
   169→            Expr::Contains {
   170→                field,
   171→                substring: sub,
   172→            },
   173→        ));
   174→    }
   175→
   176→    // Try `exists`
   177→    if let Ok((rest, _)) = tag::<&str, &str, nom::error::Error<&str>>("exists").parse(input)
   178→        && (rest.is_empty() || !is_ident_cont(rest.chars().next().unwrap_or(' ')))
   179→    {
   180→        return Ok((rest, Expr::Exists { field }));
   181→    }
   182→
   183→    // Comparison
   184→    let (input, op) = ws(cmp_op).parse(input)?;
   185→    let (input, val) = ws(value).parse(input)?;
   186→    Ok((
   187→        input,
   188→        Expr::Compare {
   189→            field,
   190→            op,
   191→            value: val,
   192→        },
   193→    ))
   194→}
   195→
   196→fn and_expr(input: &str) -> IResult<&str, Expr> {
   197→    let (input, first) = atom(input)?;
   198→    let mut result = first;
   199→    let mut remaining = input;
   200→
   201→    loop {
   202→        let trimmed = remaining.trim_start();
   203→        if let Some(rest) = trimmed.strip_prefix("&&") {
   204→            match atom(rest) {
   205→                Ok((next_remaining, next_expr)) => {
   206→                    result = Expr::And(Box::new(result), Box::new(next_expr));
   207→                    remaining = next_remaining;
   208→                }
   209→                Err(e) => return Err(e),
   210→            }
   211→        } else {
   212→            break;
   213→        }
   214→    }
   215→
   216→    Ok((remaining, result))
   217→}
   218→
   219→fn or_expr(input: &str) -> IResult<&str, Expr> {
   220→    let (input, first) = and_expr(input)?;
   221→    let mut result = first;
   222→    let mut remaining = input;
   223→
   224→    loop {
   225→        let trimmed = remaining.trim_start();
   226→        if let Some(rest) = trimmed.strip_prefix("||") {
   227→            match and_expr(rest) {
   228→                Ok((next_remaining, next_expr)) => {
   229→                    result = Expr::Or(Box::new(result), Box::new(next_expr));
   230→                    remaining = next_remaining;
   231→                }
   232→                Err(e) => return Err(e),
   233→            }
   234→        } else {
   235→            break;
   236→        }
   237→    }
   238→
   239→    Ok((remaining, result))
   240→}
   241→
   242→pub fn parse_expr(input: &str) -> Result<Expr, QueryError> {
   243→    let trimmed = input.trim();
   244→    if trimmed.is_empty() {
   245→        return Err(QueryError::EmptyExpression);
   246→    }
   247→    match or_expr(trimmed) {
   248→        Ok(("", expr)) => Ok(expr),
   249→        Ok((remaining, _)) => Err(QueryError::TrailingInput(remaining.to_string())),
   250→        Err(e) => Err(QueryError::ParseError(e.to_string())),
   251→    }
   252→}
